from typing import Any, List, Dict, Union

class ValidationError:
    def __init__(self, path: str, message: str):
        self.path = path
        self.message = message

    def __repr__(self):
        return f"[{self.path}] {self.message}"

class MiniJsonValidator:
    def __init__(self):
        self.errors: List[ValidationError] = []

    def validate(self, data: Any, schema: Dict[str, Any]) -> List[ValidationError]:
        """
        Validates data against a schema.
        Returns a list of ValidationError objects.
        """
        self.errors = []
        self._validate_recursive(data, schema, "$")
        return self.errors

    def _get_type_name(self, val: Any) -> str:
        if val is None:
            return "null"
        if isinstance(val, bool):  # Check bool before int because bool is a subclass of int
            return "boolean"
        if isinstance(val, int):
            return "integer"
        if isinstance(val, float):
            return "number"
        if isinstance(val, str):
            return "string"
        if isinstance(val, list):
            return "array"
        if isinstance(val, dict):
            return "object"
        return "unknown"

    def _validate_recursive(self, data: Any, schema: Dict[str, Any], path: str):
        if not isinstance(schema, dict):
            return

        # 1. Validate Type
        if "type" in schema:
            expected_type = schema["type"]
            actual_type = self._get_type_name(data)

            # Handle 'number' which can be int or float
            type_match = False
            if expected_type == "number":
                if actual_type in ["number", "integer"]:
                    type_match = True
            elif expected_type == actual_type:
                type_match = True

            if not type_match:
                self.errors.append(ValidationError(path, f"Expected type {expected_type}, but got {actual_type}"))
                return  # Stop validating this branch if the base type is wrong

        # 2. Validate Enum
        if "enum" in schema:
            if data not in schema["enum"]:
                self.errors.append(ValidationError(path, f"Value must be one of {schema['enum']}"))

        # 3. Type-specific validations

        # STRING
        if isinstance(data, str):
            if "minLength" in schema and len(data) < schema["minLength"]:
                self.errors.append(ValidationError(path, f"String is too short (min {schema['minLength']})"))
            if "maxLength" in schema and len(data) > schema["maxLength"]:
                self.errors.append(ValidationError(path, f"String is too long (max {schema['maxLength']})"))
            if "pattern" in schema:
                if not re.search(schema["pattern"], data):
