```python
import re
import math

# --- Grammar (BNF) ---
# <expression> ::= <term> { ("+" | "-") <term> }
# <term>       ::= <factor> { ("*" | "/") <factor> }
# <factor>     ::= "-" <factor> | <primary>
# <primary>     ::= <number>
#               | <identifier> "(" <expression> ")"
#               | <identifier>
#               | "(" <expression> ")"
# <number>     ::= <digit> { <digit> } [ "." { <digit> } ]
# <identifier>  ::= <letter> { <letter> | <digit> }

class ExpressionError(Exception):
    """Base class for errors in the expression evaluator."""
    def __init__(self, message, position):
        self.position = position
        super().__init__(f"{message} at position {position}")

class ParseError(ExpressionError):
    """Errors related to syntax (e.g., mismatched parentheses)."""
    pass

class RuntimeError(ExpressionError):
    """Errors related to evaluation (e.g., unknown variables)."""
    pass

class Token:
    def __init__(self, type, value, pos):
        self.type = type
        self.value = value
        self.pos = pos

    def __repr__(self):
        return f"Token({self.type}, {self.value}, {self.pos})"

class Lexer:
    """Converts raw string input into a list of Tokens."""
    TOKEN_SPEC = [
        ('NUMBER',   r'\d+(\.\d+)?'),    # Integer or decimal number
        ('ID',       r'[a-zA-Z_]\w*'),    # Identifiers (variables/functions)
        ('PLUS',    r'\+'),            # Addition
        ('MINUS',    r'-'),              # Subtraction
        ('MUL',      r'\*'),            # Multiplication
        ('DIV',      r'/'),               # Division
        ('LPAREN',   r'\('),             # Left Parenthesis
        ('RPAREN',   r'\)'),             # Right Parenthesis
        ('WS',       r'\s+'),        # Whitespace (to be ignored)
        ('MISMATCH', r'.'),              # Any other character
    ]

    def __init__(self, text):
        self.text = text
        self.tokens = []
        self._tokenize()

    def _tokenize(self):
        regex = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in self.TOKEN_SPEC)
        for mo in re.finditer(regex, self.text):
            kind = mo.lastgroup
            value = mo.group()
            pos = mo.start()
            if kind == 'NUMBER':
                self.tokens.append(Token('NUMBER', float(value), pos))
            elif kind == 'ID':
                self.tokens.append(Token('ID', value, pos))
            elif kind in ('PLUS', 'MINUS', 'MUL', 'DIV', 'LPAREN', 'RPAREN'):
                self.tokens.append(Token(kind, value, pos))
            elif kind == 'WS':
                continue
            elif kind == 'MISMATCH':
                raise ParseError(f"Unexpected character '{value}'", pos)
        self.tokens.append(Token('EOF', None, len(self.text)))

class Parser:
    """Recursive descent parser that evaluates expressions on the fly."""
    def __init__(self, tokens, variables=None, functions=None):
        self.tokens = tokens
        self.pos = 0
        self.variables = variables if variables is not None else {}
        self.functions = functions if functions is not None else {
            'sin': math.sin,
            'cos': math.cos,
            'sqrt': math.sqrt
        }

    def _peek(self, offset=0):
        """Look at a token at a specific offset from current position."""
        idx = self.pos + offset
        if idx < len(self.tokens):
            return self.tokens[idx]
        return self.tokens[-1] # Should be EOF

    def _eat(self, expected_type):
        """Consume a token if it matches the expected type, else raise error."""
        token = self._peek()
        if token.type == expected_type:
            self.pos += 1
            return token
        else:
            raise ParseError(f"Expected {expected_type} but found {token.type}", token.pos)

    def evaluate(self):
        result = self._expression()
        if self._peek().type != 'EOF':
            raise ParseError("Unexpected trailing data", self._peek().pos)
        return result

    def _expression(self):
        """Handles + and - (lowest precedence)."""
        node = self._term()
        while self._peek().type in ('PLUS', 'MINUS'):
            token = self._peek()
            self.pos += 1
            if token.type == 'PLUS':
                node += self._term()
            else:
                node -= self._term()
        return node

    def _term(self):
        """Handles * and /."""
        node = self._factor()
        while self._peek().type in ('MUL', 'DIV'):
            token = self._peek()
            self.pos += 1
            if token.type == 'MUL':
                node *= self._factor()
            else:
                divisor = self._factor()
                if divisor == 0:
                    raise RuntimeError("Division by zero", token.pos)
                node /= divisor
        return node

    def _factor(self):
        """Handles unary minus."""
        token = self._peek()
        if token.type == 'MINUS':
            self.pos += 1
            return -self._factor()
        return self._primary()

    def _primary(self):
        """Handles numbers, variables, functions, and parentheses."""
        token = self._peek()

        if token.type == 'NUMBER':
            self.pos += 1
            return token.value

        if token.type == 'LPAREN':
            self.pos += 1
            val = self._expression()
            if self._peek().type != 'RPAREN':
                raise ParseError("Mismatched parentheses: missing ')'", token.pos)
            self.pos += 1 # Consume RPAREN
            return val

        if token.type == 'ID':
            name = token.value
            start_pos = token.pos
            self.pos += 1

            # Check if it's a function call: identifier '('
            if self._peek().type == 'LPAREN':
                if name not in self.functions:
                    raise RuntimeError(f"Unknown function '{name}'", start_pos)
                self.pos += 1 # Consume LPAREN
                arg = self._expression()
                if self._peek().type != 'RPAREN':
                    raise ParseError("Mismatched parentheses: missing ')' after function argument", token.pos)
                self.pos += 1 # Consume RPAREN
                return self.functions[name](arg)
            else:
                # It's a variable
                if name not in self.variables:
                    raise RuntimeError(f"Unknown variable '{name}'", start_pos)
                return self.variables[name]

        raise ParseError(f"Unexpected token {token.type}", token.pos)

def evaluate_expression(expr, vars=None):
    """Helper function to run the parser."""
    lexer = Lexer(expr)
    parser = Parser(lexer.tokens, variables=vars)
    return parser.evaluate()

# --- Test Suite ---
def run_tests():
    test_cases = [
        # Normal cases
        ("1 + 2 * 3", None, 7.0),
        ("(1 + 2) * 3", None, 9.0),
        ("-5 + 2", None, -3.0),
        ("--5", None, 5.0),
        ("10 / 4", None, 2.5),
        ("x + y", {'x': 10, 'y': 5}, 15.0),
        ("sin(0) + cos(0)", None, 1.0),
        ("sqrt(16) * 2", None, 8.0),

        # Error cases: Parse Errors
        ("(1 + 2", None, "ParseError"),
        ("1 + (2 * 3", None, "ParseError"),
        ("1 + * 2", None, "ParseError"),
        ("((1))", None, 1.0), # Nested parens

        # Error cases: Runtime Errors
        ("1 / 0", None, "RuntimeError"),
        ("a + 1", None, "RuntimeError"), # Unknown variable
        ("unknown_func(1)", None, "RuntimeError"), # Unknown function
    ]

    print(f"{'Expression':<20} | {'Expected':<10} | {'Result':<10} | {'Status'}")
    print("-" * 60)

    for expr, vars, expected in test_cases:
        try:
            result = evaluate_expression(expr, vars)
            if isinstance(expected, str) and expected in ("ParseError", "RuntimeError"):
                status = "FAIL (Expected Error)"
            elif result == expected:
                status = "PASS"
            else:
                status = f"FAIL (Got {result})"
        except (ParseError, RuntimeError) as e:
            if isinstance(expected, str) and expected in ("ParseError", "RuntimeError"):
                status = "PASS (Caught Error)"
            else:
                status = f"FAIL (Unexpected Error: {e})"
            result = str(e)
        except Exception as e:
            status = f"FAIL (Unexpected Exception: {type(e).__name__})"
            result = str(e)

        print(f"{expr:<20} | {str(expected):<10} | {str(result):<10} | {status}")

if __name__ == "__main__":
    run_tests()
```

### Key Features of this Implementation:

1.  **Grammar Implementation**:
    *   The `_expression` method handles addition and subtraction.
    *   The `_term` method handles multiplication and division.
    *   The `_factor` method handles unary minus by calling itself recursively, allowing for expressions like `--5`.
    *   The `_primary` method handles the "atoms" of the expression: numbers, variables, function calls, and parenthesized sub-expressions.

2.  **Operator Precedence**:
    *   Precedence is naturally handled by the hierarchy of function calls: `expression` $\to$ `term` $\to$ `factor` $\to$ `primary`. This ensures that `*` is evaluated before `+`, and unary `-` is evaluated before multiplication.

3.  **Error Handling**:
    *   **`ParseError`**: Raised when the syntax is invalid (e.g., `1 + * 2` or `(1 + 2`). It includes the character position.
    *   **`RuntimeError`**: Raised when the syntax is correct but the evaluation fails (e.g., `1 / 0` or using a variable `x` that wasn't provided in the dictionary).
    *   **Position Tracking**: Every token stores its starting index in the string, allowing the error messages to point exactly where the problem occurred.

4.  **Function and Variable Support**:
    *   The parser distinguishes between a variable and a function call by looking ahead one token. If an identifier is followed by `(`, it is treated as a function; otherwise, it is treated as a variable.

5.  **Complexity**:
    *   **Time Complexity**: $O(n)$, where $n$ is the length of the string, as each token is visited a constant number of times.
    *   **Space Complexity**: $O(n)$ for the token list and the recursion stack.

