```python
import re

class MiniJSONValidator:
    def __init__(self):
        self.errors = []

    def validate(self, data, schema):
        """
        Main entry point.
        Returns a list of errors: [{"path": "...", "message": "..."}]
        """
        self.errors = []
        self._traverse(data, schema, "$")
        return self.errors

    def _add_error(self, path, message):
        self.errors.append({"path": path, "message": message})

    def _traverse(self, data, schema, path):
        if not isinstance(schema, dict):
            return

        # 1. Validate Type
        target_type = schema.get("type")
        if target_type:
            if not self._check_type(data, target_type):
                self._add_error(path, f"Expected type {target_type}, got {type(data).__name__}")
                return  # Stop traversing this branch if type is wrong

        # 2. Validate Enum
        if "enum" in schema:
            if data not in schema["enum"]:
                self._add_error(path, f"Value {data} not in allowed enum: {schema['enum']}")

        # 3. Validate String Constraints
        if isinstance(data, str):
            if "minLength" in schema and len(data) < schema["minLength"]:
                self._add_error(path, f"String too short (min {schema['minLength']})")
            if "maxLength" in schema and len(data) > schema["maxLength"]:
                self._add_error(path, f"String too long (max {schema['maxLength']})")
            if "pattern" in schema:
                if not re.search(schema["pattern"], data):
                    self._add_error(path, f"String does not match pattern: {schema['pattern']}")

        # 4. Validate Number Constraints
        if isinstance(data, (int, float)) and not isinstance(data, bool):
            if "minimum" in schema and data < schema["minimum"]:
                self._add_error(path, f"Value {data} is less than minimum {schema['minimum']}")
            if "maximum" in schema and data > schema["maximum"]:
                self._add_error(path, f"Value {data} is greater than maximum {schema['maximum']}")

        # 5. Validate Object Constraints
        if isinstance(data, dict):
            # Check required properties
            if "required" in schema:
                for req_key in schema["required"]:
                    if req_key not in data:
                        self._add_error(f"{path}.{req_key}", f"Required property '{req_key}' is missing")

            # Check properties recursion
            if "properties" in schema:
                for key, sub_schema in schema["properties"].items():
                    if key in data:
                        self._traverse(data[key], sub_schema, f"{path}.{key}")

        # 6. Validate Array Constraints
        if isinstance(data, list):
            if "items" in schema:
                item_schema = schema["items"]
                for i, item in enumerate(data):
                    self._traverse(item, item_schema, f"{path}[{i}]")

    def _check_type(self, data, target_type):
        # Mapping JSON Schema types to Python types
        type_map = {
            "object": dict,
            "array": list,
            "string": str,
            "number": (int, float),
            "integer": int,
            "boolean": bool,
            "null": type(None)
        }

        expected = type_map.get(target_type)
        if expected is None:
            return True # Unknown type in schema, skip validation

        # Special case: In Python, bool is a subclass of int. 
        # We must ensure 'integer' doesn't accept 'True/False'.
        if target_type == "integer":
            return isinstance(data, int) and not isinstance(data, bool)

        if target_type == "number":
            # If target is number, we allow int or float, but not bool
            if isinstance(data, bool):
                return False
            return isinstance(data, expected)

        return isinstance(data, expected)

# --- Test Suite ---

def run_tests():
    validator = MiniJSONValidator()

    test_cases = [
        {
            "name": "Valid simple object",
            "schema": {
                "type": "object",
                "properties": {
                    "id": {"type": "integer"},
                    "name": {"type": "string", "minLength": 3}
                },
                "required": ["id"]
            },
            "data": {"id": 1, "name": "Alice"},
            "expected_error_count": 0
        },
        {
            "name": "Invalid types and missing required",
            "schema": {
                "type": "object",
                "properties": {
                    "age": {"type": "integer"},
                    "email": {"type": "string", "pattern": r"@"}
                },
                "required": ["age", "email"]
            },
            "data": {"age": "twenty"}, # Wrong type, missing email
            "expected_error_count": 2
        },
        {
            "name": "String constraints (length and pattern)",
            "schema": {
                "type": "string",
                "minLength": 5,
                "maxLength": 10,
                "pattern": "^[A-Z]+$"
            },
            "data": "abc", # Too short, wrong pattern
            "expected_error_count": 2
        },
        {
            "name": "Array validation",
            "schema": {
                "type": "array",
                "items": {"type": "integer", "maximum": 10}
            },
            "data": [1, 5, 15], # 15 is too large
            "expected_error_count": 1
        },
        {
            "name": "Nested object and Enum",
            "schema": {
                "type": "object",
                "properties": {
                    "user": {
                        "type": "object",
                        "properties": {
                            "role": {"type": "string", "enum": ["admin", "user"]}
                        }
                    }
                }
            },
            "data": {"user": {"role": "guest"}}, # 'guest' not in enum
            "expected_error_count": 1
        },
        {
            "name": "Number range and Null",
            "schema": {
                "type": "object",
                "properties": {
                    "score": {"type": "number", "minimum": 0, "maximum": 100},
                    "metadata": {"type": "null"}
                }
            },
            "data": {"score": -5, "metadata": "not-null"},
            "expected_error_count": 2
        }
    ]

    for tc in test_cases:
        errors = validator.validate(tc["data"], tc["schema"])
        passed = len(errors) == tc["expected_error_count"]
        status = "✅ PASS" if passed else "❌ FAIL"
        print(f"{status} | {tc['name']} (Found {len(errors)} errors)")
        if not passed:
            for err in errors:
                print(f"   -> {err}")

if __name__ == "__main__":
    run_tests()
```

### Discussion

#### What was implemented:
1.  **Recursive Traversal**: The validator walks through nested objects and arrays.
2.  **Type Checking**: A robust type checker that distinguishes between `integer` and `boolean` (a common pitfall in Python where `isinstance(True, int)` is `True`).
3.  **Error Accumulation**: Instead of raising an exception, it appends to a list, allowing the user to see all schema violations in one pass.
4.  **Path Tracking**: It maintains a string path (e.g., `$.user.role` or `$[0].id`) to pinpoint exactly where the error occurred.
5.  **Core Keywords**: `type`, `properties`, `items`, `required`, `enum`, `minimum`, `maximum`, `minLength`, `maxLength`, and `pattern`.

#### What was NOT implemented and why:

1.  **Logical Combinators (`anyOf`, `allOf`, `oneOf`, `not`)**:
    *   *Reason*: These require complex branching logic. Implementing `anyOf` requires attempting to validate against multiple sub-schemas and managing the "success" state across different branches, which significantly increases code complexity.
2.  **`additionalProperties`**:
    *   *Reason*: To implement this, the validator would need to check every key in the input data against the keys defined in the `properties` schema and flag any that don't match. This requires a separate loop over the input dictionary keys.
3.  **`format`**:
    *   *Reason*: `format` (e.g., `format: "email"`) is semantic validation. It requires a library of regex patterns or date-parsing logic for many different types (date-time, email, ipv4, etc.).
4.  **`dependencies` and `if/then/else`**:
    *   *Reason*: These introduce conditional validation logic (e.g., "if field X exists, then field Y is required"). This requires a two-pass approach or a more complex state machine during traversal.
5.  **`multipleOf`**:
    *   *Reason*: This requires mathematical modulo operations on numbers, which is simple but adds another layer of keyword handling.
6.  **`const`**:
    *   *Reason*: While simple to implement (it's just an `enum` with one value), it was omitted to keep the implementation focused on the core structural requirements.

