import math
import re

"""
GRAMMAR (BNF):
---------------------------------------------------------
expression  ::= term { ("+" | "-") term }
term      ::= factor { ("*" | "/") factor }
factor    ::= "-" factor | primary
primary   ::= NUMBER 
            | ID "(" expression ")"  (Function call)
            | ID                  (Variable)
            | "(" expression ")"
---------------------------------------------------------
Precedence (Highest to Lowest):
1. Parentheses / Function calls
2. Unary Minus (-)
3. Multiplication (*) and Division (/)
4. Addition (+) and Subtraction (-)
"""

class ExpressionError(Exception):
    """Custom exception for parsing and evaluation errors."""
    def __init__(self, message, position=None):
        self.position = position
        full_msg = f"Error at position {position}: {message}" if position is not None else message
        super().__init__(full_msg)

class Token:
    def __init__(self, type, value, pos):
        self.type = type
        self.value = value
        self.pos = pos

    def __repr__(self):
        return f"Token({self.type}, {self.value}, {self.pos})"

class Lexer:
    """Breaks the input string into a stream of tokens."""
    TOKEN_SPEC = [
        ('NUMBER',   r'\d+(\.\d+)?'),      # Integer or decimal number
        ('ID',       r'[a-zA-Z_]\w*'),  # Identifiers (variables/functions)
        ('PLUS',    r'\+'),
        ('MINUS',    r'-'),
        ('MUL',     r'\*'),
        ('DIV',      r'/'),
        ('LPAREN',  r'\('),
        ('RPAREN',  r'\)'),
        ('WS',       r'\s+'),              # Whitespace (to be ignored)
        ('MISMATCH', r'.'),               # Any other character
    ]

    def __init__(self, text):
        self.text = text
        self.tokens = []

    def tokenize(self):
        regex = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in self.TOKEN_SPEC)
        for mo in re.finditer(regex, self.text):
            kind = mo.lastgroup
            value = mo.group()
            pos = mo.start()
            if kind == 'WS':
                continue
            elif kind == 'MISMATCH':
                raise ExpressionError(f"Unexpected character '{value}'", pos)
            self.tokens.append(Token(kind, value, pos))
        self.tokens.append(Token('EOF', None, len(self.text)))
        return self.tokens

class Parser:
    """
    Recursive Descent Parser that evaluates the expression 
    on the fly during parsing.
    """
    def __init__(self, tokens, variables=None):
        self.tokens = tokens
        self.variables = variables or {}
        self.pos = 0

    def peek(self):
        return self.tokens[self.pos]

    def eat(self, expected_type=None):
        token = self.peek()
        if expected_type and token.type != expected_type:
            raise ExpressionError(f"Expected {expected_type} but found {token.type}", token.pos)
        self.pos += 1
        return token

    def parse(self):
        result = self.expression()
        if self.peek().type != 'EOF':
            raise ExpressionError(f"Unexpected token {self.peek().type}", self.peek().pos)
        return result

    def expression(self):
        # expr ::= term { ("+" | "-") term }
        node = self.term()
        while self.peek().type in ('PLUS', 'MINUS'):
            op_token = self.eat()
            right = self.term()
            if op_token.type == 'PLUS':
                node += right
            else:
                node -= right
        return node

    def term(self):
        # term ::= factor { ("*" | "/") factor }
        node = self.factor()
        while self.peek().type in ('MUL', 'DIV'):
            op_token = self.eat()
            right = self.factor()
            if op_token.type == 'MUL':
                node *= right
            else:
                if right == 0:
                    raise ZeroDivisionError("Division by zero")
                node /= right
        return node

    def factor(self):
        # factor ::= "-" factor | primary
        if self.peek().type == 'MINUS':
            self.eat('MINUS')
            return -self.factor()
        return self.primary()

    def primary(self):
        token = self.peek()

        # Case: ( expression )
        if token.type == 'LPAREN':
            self.eat('LPAREN')
            result = self.expression()
            if self.peek().type != 'RPAREN':
                raise ExpressionError("Mismatched parentheses: missing ')'", token.pos)
            self.eat('RPAREN')
            return result

        # Case: NUMBER
        elif token.type == 'NUMBER':
            val = float(self.eat('NUMBER').value)
            return val

        # Case: ID (Variable or Function)
        elif token.type == 'ID':
            name = self.eat('ID').value
            # Check if it's a function call: ID '('
            if self.peek().type == 'LPAREN':
                self.eat('LPAREN')
                arg = self.expression()
                if self.peek().type != 'RPAREN':
                    raise ExpressionError("Mismatched parentheses in function call", token.pos)
                self.eat('RPAREN')

                # Function mapping
                if name == 'sin': return math.sin(arg)
                if name == 'cos': return math.cos(arg)
                if name == 'sqrt': 
                    if arg < 0: raise ValueError("math domain error: sqrt of negative number")
                    return math.sqrt(arg)
                raise ExpressionError(f"Unknown function '{name}'", token.pos)
            else:
                # It's a variable
                if name not in self.variables:
                    raise NameError(f"Unknown variable '{name}'")
                return self.variables[name]

        else:
            raise ExpressionError(f"Unexpected token {token.type}", token.pos)

def evaluate(expression_str, variables=None):
    lexer = Lexer(expression_str)
    tokens = lexer.tokenize()
    parser = Parser(tokens, variables)
    return parser.parse()

# ==========================================
# TEST SUITE
# ==========================================

def run_tests():
    print("--- Starting Tests ---\n")

    # 1. Normal Cases
    print("Test 1: Basic Arithmetic")
    assert evaluate("10 + 5 * 2") == 20.0
    assert evaluate("(10 + 5) * 2") == 30.0
    print("  [PASS]")

    print("Test 2: Unary Minus")
    assert evaluate("-5 + 3") == -2.0
    assert evaluate("5 + -(-3)") == 8.0
    print("  [PASS]")

    print("Test 3: Floating Point")
    assert evaluate("2.5 * 2") == 5.0
    assert evaluate("10 / 4") == 2.5
    print("  [PASS]")

    print("Test 4: Functions")
    # sin(0) = 0, cos(0) = 1
    assert abs(evaluate("sin(0) + cos(0)") - 1.0) < 1e-9
    assert evaluate("sqrt(16)") == 4.0
    print("  [PASS]")

    print("Test 5: Variables")
    vars_dict = {'x': 10, 'y': 2.5}
    assert evaluate("x * y", vars_dict) == 25.0
    assert evaluate("x + y", vars_dict) == 12.5
    print("  [PASS]")

    # 2. Error Cases
    print("\n--- Testing Error Handling ---")

    print("Test 6: Mismatched Parentheses (Syntax Error)")
    try:
        evaluate("(1 + 2")
    except ExpressionError as e:
        print(f"  [PASS] Caught expected error: {e}")
    else:
        print("  [FAIL] Did not catch mismatched parenthesis")

    print("Test 7: Unknown Identifier (Name Error)")
    try:
        evaluate("a + 5")
    except NameError as e:
        print(f"  [PASS] Caught expected error: {e}")
    else:
        print("  [FAIL] Did not catch unknown variable")

    print("Test 8: Unknown Function (Name Error)")
    try:
        evaluate("unknown_func(5)")
    except ExpressionError as e:
        print(f"  [PASS] Caught expected error: {e}")
    else:
