/**
 * @param {Function} fn - The function to debounce.
 * @param {number} ms - The delay in milliseconds.
 * @returns {Function} - The debounced version of the function.
 */
function debounce(fn, ms) {
  // 1. This variable is stored in the closure. 
  // It keeps track of the timer so we can reset it on every call.
  let timeoutId;

  // 2. We return a new function. This is the function the user will actually call.
  return function(...args) {
    // 3. 'this' refers to the context in which the debounced function is called.
    // We capture it to ensure the original function has the correct 'this' context.
    const context = this;

    // 4. If the function is called again before the delay (ms) has passed,
    // we clear the previous timer. This "resets" the clock.
    clearTimeout(timeoutId);

    // 5. We start a new timer.
    timeoutId = setTimeout(() => {
      // 6. Once the timer finally completes, we execute the original function.
      // We use .apply() to pass the correct 'this' context and all arguments.
      fn.apply(context, args);
    }, ms);
  };
}

